import {
  AppInstallationApiResponse,
  AppInstallationListApiResponse,
  InstallAppRequest,
  InstallationEstimateApiResponse,
  InstallationListQueryParams,
  UpdateAppConfigurationRequest,
  UpdateInstallationEnabledRequest,
} from '../models/api/app-store-api.models';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Injectable, inject } from '@angular/core';
import { Observable, map } from 'rxjs';

import { InstallationEstimate } from '../models/app-store.models';
import { ApiUrlService } from '../../../core/services/api-url.service';
import { isDefined } from '../../../shared/utils';

/**
 * Frontend model for app installation
 */
export interface AppInstallation {
  id: string;
  ownerId: string;
  appId: string;
  appName: string;
  screenIds: string[];
  isEnabled: boolean;
  configuration: Record<string, unknown>;
  createdAt: string;
  updatedAt: string;
  pendingFeeAcknowledgement: boolean;
}

/**
 * Configuration options for a specific integration point
 */
export interface IntegrationPointConfig {
  /** Material icon name or URL (default: "browser") */
  icon?: string;
  /** UI section placement (default: "Apps") */
  section?: string;
  /** Display order (default: 0) */
  order?: string | number;
}

/**
 * Configuration for external app installation
 * Nested by integration point to prevent key collisions
 */
export interface ExternalAppConfiguration {
  /** Configuration for appSidebar integration point */
  appSidebar?: IntegrationPointConfig;
  /** Allow other integration points */
  [key: string]: IntegrationPointConfig | undefined;
}

/**
 * Service for managing app installations
 */
@Injectable({
  providedIn: 'root',
})
export class AppInstallationService {
  private readonly http = inject(HttpClient);
  private readonly apiUrlService = inject(ApiUrlService);
  private readonly baseUrl = `${this.apiUrlService.getCurrentApiUrl()}/telemetrystore/installations`;

  /**
   * Get all app installations for a user/organization
   * @param params Query parameters for filtering
   */
  getInstallations(
    params?: InstallationListQueryParams,
  ): Observable<AppInstallation[]> {
    let httpParams = new HttpParams();

    if (params) {
      if (params.owner !== undefined) {
        httpParams = httpParams.set('owner', params.owner);
      }
      if (params.offset !== undefined) {
        httpParams = httpParams.set('offset', params.offset.toString());
      }
      if (params.limit !== undefined) {
        httpParams = httpParams.set('limit', params.limit.toString());
      }
      if (params.sort !== undefined) {
        httpParams = httpParams.set('sort', params.sort);
      }
      if (params.filter !== undefined) {
        httpParams = httpParams.set('filter', params.filter);
      }
    }

    return this.http
      .get<AppInstallationListApiResponse>(this.baseUrl, {
        params: httpParams,
      })
      .pipe(
        map((response) =>
          response.items
            .filter((item) => item != null)
            .map((item) => this.mapFromApi(item)),
        ),
      );
  }

  /**
   * Get a specific installation by ID
   * @param id Installation ID
   * @param owner Optional owner filter
   */
  getInstallation(
    id: string,
    owner?: string,
  ): Observable<AppInstallation | null> {
    let httpParams = new HttpParams();
    if (owner !== undefined) {
      httpParams = httpParams.set('owner', owner);
    }

    return this.http
      .get<AppInstallationApiResponse>(`${this.baseUrl}/${id}`, {
        params: httpParams,
      })
      .pipe(map((response) => this.mapFromApi(response)));
  }

  /**
   * Install an app for a user/organization
   * @param appId The app to install
   * @param ownerId The owner (user/org) installing the app
   * @param configuration Optional initial configuration
   */
  installApp(
    appId: string,
    ownerId: string,
    configuration?: Record<string, unknown>,
  ): Observable<AppInstallation> {
    const request: InstallAppRequest = {
      appId,
      ownerId,
      configuration,
    };

    return this.http
      .post<AppInstallationApiResponse>(this.baseUrl, request)
      .pipe(map((response) => this.mapFromApi(response)));
  }

  /**
   * Install an external app (appSidebar) with automatic external tab configuration
   * This endpoint atomically creates the installation and adds the external tab to client flags
   * If any step fails, all changes are automatically rolled back using saga pattern
   * @param appId The app to install
   * @param ownerId The owner (user/org) installing the app
   * @param configuration Optional configuration nested by integration point
   *                      Example: { appSidebar: { icon: 'chart', section: 'ANALYTICS', order: 5 } }
   *                      If not provided, backend uses defaults: icon="browser", section="Apps", order=0
   */
  installExternalApp(
    appId: string,
    ownerId: string,
    configuration?: ExternalAppConfiguration,
  ): Observable<AppInstallation> {
    const request: InstallAppRequest = {
      appId,
      ownerId,
      configuration: configuration,
    };

    const externalInstallationsUrl = `${this.apiUrlService.getCurrentApiUrl()}/telemetrystore/external-installations`;

    return this.http
      .post<AppInstallationApiResponse>(externalInstallationsUrl, request)
      .pipe(map((response) => this.mapFromApi(response)));
  }

  /**
   * Uninstall an external app (appSidebar) with automatic external tab removal
   * This endpoint atomically removes the installation and the external tab from client flags
   * If any step fails, all changes are automatically rolled back using saga pattern
   * @param id Installation ID
   * @param owner Owner (client) ID
   */
  uninstallExternalApp(id: string, owner: string): Observable<AppInstallation> {
    const httpParams = new HttpParams().set('owner', owner);
    const externalInstallationsUrl = `${this.apiUrlService.getCurrentApiUrl()}/telemetrystore/external-installations/${id}`;

    return this.http
      .delete<AppInstallationApiResponse>(externalInstallationsUrl, {
        params: httpParams,
      })
      .pipe(map((response) => this.mapFromApi(response)));
  }

  /**
   * Uninstall an app
   * @param id Installation ID
   * @param owner Optional owner filter
   */
  uninstallApp(id: string, owner: string): Observable<AppInstallation> {
    const httpParams = new HttpParams().set('owner', owner);

    return this.http
      .delete<AppInstallationApiResponse>(`${this.baseUrl}/${id}`, {
        params: httpParams,
      })
      .pipe(map((response) => this.mapFromApi(response)));
  }

  /**
   * Update app configuration
   * @param id Installation ID
   * @param ownerId Owner ID
   * @param configuration New configuration
   */
  updateConfiguration(
    id: string,
    ownerId: string,
    configuration: Record<string, unknown>,
  ): Observable<AppInstallation> {
    const request: UpdateAppConfigurationRequest = {
      ownerId,
      configuration,
    };

    return this.http
      .put<AppInstallationApiResponse>(`${this.baseUrl}/${id}/config`, request)
      .pipe(map((response) => this.mapFromApi(response)));
  }

  /**
   * Enable or disable an installed app
   * @param id Installation ID
   * @param ownerId Owner ID
   * @param isEnabled Whether the app should be enabled
   */
  setEnabled(
    id: string,
    ownerId: string,
    isEnabled: boolean,
  ): Observable<AppInstallation> {
    const request: UpdateInstallationEnabledRequest = { ownerId, isEnabled };
    return this.http
      .put<AppInstallationApiResponse>(`${this.baseUrl}/${id}`, request)
      .pipe(map((response) => this.mapFromApi(response)));
  }

  /**
   * Get all installations for a specific app (creator view)
   * @param appId The app to fetch installations for
   */
  getAppInstallations(appId: string): Observable<AppInstallation[]> {
    return this.http
      .get<AppInstallationListApiResponse>(
        `${this.apiUrlService.getCurrentApiUrl()}/telemetrystore/apps/${appId}/installations`,
      )
      .pipe(
        map((response) =>
          response.items
            .filter((item) => isDefined(item))
            .map((item) => this.mapFromApi(item)),
        ),
      );
  }

  /**
   * Maps API response to frontend model
   */
  private mapFromApi(apiResponse: AppInstallationApiResponse): AppInstallation {
    return {
      id: apiResponse.id,
      ownerId: apiResponse.ownerId,
      appId: apiResponse.appId,
      appName: apiResponse.appName,
      screenIds: apiResponse.screenIds,
      isEnabled: apiResponse.isEnabled,
      configuration: apiResponse.configuration,
      createdAt: apiResponse.createdDate,
      updatedAt: apiResponse.updatedDate,
      pendingFeeAcknowledgement: apiResponse.pendingFeeAcknowledgement,
    };
  }

  getInstallationEstimate(appId: string, ownerId: string): Observable<InstallationEstimate> {
    const httpParams = new HttpParams().set('owner', ownerId);
    return this.http
      .get<InstallationEstimateApiResponse>(
        `${this.apiUrlService.getCurrentApiUrl()}/telemetrystore/apps/${appId}/installation-estimate`,
        { params: httpParams },
      )
      .pipe(map((r) => this.mapEstimateFromApi(r)));
  }

  private mapEstimateFromApi(r: InstallationEstimateApiResponse): InstallationEstimate {
    return {
      appId: r.appId,
      ownerId: r.ownerId,
      feeModel: r.feeModel,
      activeDeviceCount: r.activeDeviceCount,
      estimatedCost: r.estimatedCost,
    };
  }

  acknowledgeFee(installationId: string, ownerId: string): Observable<AppInstallation> {
    return this.http
      .post<AppInstallationApiResponse>(
        `${this.baseUrl}/${installationId}/acknowledge-fee`,
        { ownerId },
      )
      .pipe(map((response) => this.mapFromApi(response)));
  }
}
